#include <bits/stdc++.h>
using namespace std;
const int N=10,M=55;
int dp1[M][1<<N][1<<N],dp[M][1<<N][1<<N],sum[M][1<<N],a[M][N],n,m,ans1=0x3f3f3f3f,ans2=0x3f3f3f3f;
int fun(int x)
{
	int cnt=0;
	while(x)
	{
		if(x%2) cnt++;
		x/=2;
	}
	return cnt;
}
int main()
{
	cin>>n>>m;
	memset(dp1,0x3f,sizeof(dp1));
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++) cin>>a[i][j];
	}
	int t=1<<m;
	for(int i=1;i<=n;i++)
	{
		for(int j=0;j<t;j++)
		{
			for(int k=0;k<m;k++)
			{
				if(j&(1<<k)) sum[i][j]+=a[i][k+1];
			}
		}
	}
	for(int i=0;i<t;i++) dp1[1][i][0]=sum[1][i],dp[1][i][0]=fun(i);
	for(int i=2;i<=n;i++)
	{
		for(int j=0;j<t;j++)
		{
			for(int k=0;k<t;k++)
			{
				for(int k2=0;k2<t;k2++)
				{
					if(((j|k|k2|(k<<1)|(k>>1))&t-1)==t-1)
					{
						int t1=dp1[i-1][k][k2]+sum[i][j],t2=dp[i-1][k][k2]+fun(j);
						if(dp1[i][j][k]>t1||dp1[i][j][k]==t1&&dp[i][j][k]>t2) dp1[i][j][k]=t1,dp[i][j][k]=t2;
					}
				}
			}
		}
	}
	for(int i=0;i<t;i++)
	{
		for(int j=0;j<t;j++)
		{
			if((((i|j|(i<<1)|(i>>1))&t-1)==t-1)&&(ans2>dp1[n][i][j]||dp1[n][i][j]==ans2&&dp[n][i][j]<ans1)) ans2=dp1[n][i][j],ans1=dp[n][i][j];
		}
	}
	cout<<ans1<<" "<<ans2;
	return 0;
}
